import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.ActorMaterializer
import spray.json._

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("webhook-proxy-service")
    implicit val materializer = ActorMaterializer()
    implicit val jsonFormat = JsonFormat.Default

    val route =
      path("webhook") {
        post {
          entity(as[JsValue]) { userUrl =>
            val request = HttpRequest(uri = userUrl)
            val responseFuture = Http().singleRequest(request)

            onComplete(responseFuture) {
              case Success(response) => complete(response)
              case Failure(t) => complete(StatusCodes.InternalServerError, s"Error fetching content: $t")
            }
          }
        }
      }

    val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
    println(s"Server online at http://localhost:8080/webhook")
  }
}